const numbersToWords=s=>{const M=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(s<0x14)return M[s];if(s<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](s/0xa)]+(s%0xa?'\x20'+M[s%0xa]:'');if(s<0x3e8){const E=Math['floor'](s/0x64),w=s%0x64;return(0x1===E?'εκατό':0x2===E?'διακόσια':0x3===E?'τριακόσια':0x4===E?'τετρακόσια':0x5===E?'πεντακόσια':0x6===E?'εξακόσια':0x7===E?'επτακόσια':0x8===E?'οκτακόσια':0x9===E?'εννιακόσια':'')+(w?'\x20'+numbersToWords(w):'');}return s<0xf4240?numbersToWords(Math['floor'](s/0x3e8))+'\x20χιλιάδες'+(s%0x3e8?'\x20'+numbersToWords(s%0x3e8):''):numbersToWords(Math['floor'](s/0xf4240))+'\x20εκατομμύρια'+(s%0xf4240?'\x20'+numbersToWords(s%0xf4240):'');},numberToText=(M,E='money')=>{const w=Math['floor'](M),F=Math['round'](0x64*(M-w));let A=numbersToWords(w),y=F>0x0?numbersToWords(F):'';switch(E){case'money':return y?A+'\x20ευρώ\x20και\x20'+y+'\x20λεπτά':A+'\x20ευρώ';case'time':return y?A+'\x20ώρες\x20και\x20'+y+'\x20λεπτά':A+'\x20ώρες';default:return y?A+'\x20και\x20'+y:''+A;}};